export interface RepoCoordinates {
  owner: string;
  repo: string;
}

export const parseGitHubUrl = (url: string): RepoCoordinates | null => {
  try {
    const urlObj = new URL(url);
    const parts = urlObj.pathname.split('/').filter(Boolean);
    if (parts.length >= 2) {
      return { owner: parts[0], repo: parts[1] };
    }
  } catch (e) {
    return null;
  }
  return null;
};

export const fetchGitHubRepoContext = async (url: string): Promise<string> => {
  const coords = parseGitHubUrl(url);
  if (!coords) throw new Error("Invalid GitHub URL structure. Expected format: https://github.com/owner/repo");

  const { owner, repo } = coords;
  const baseUrl = `https://api.github.com/repos/${owner}/${repo}`;

  const [readmeRes, contentsRes] = await Promise.all([
    fetch(`${baseUrl}/readme`),
    fetch(`${baseUrl}/contents`)
  ]);

  let contextBuilder = `REPOSITORY ANALYSIS TARGET: ${owner}/${repo}\n\n`;

  if (contentsRes.ok) {
    const files = await contentsRes.json();
    if (Array.isArray(files)) {
      const fileList = files.map((f: any) => `- ${f.name} [${f.type}]`).join('\n');
      contextBuilder += `ROOT DIRECTORY STRUCTURE:\n${fileList}\n\n`;
    }
  } else {
    contextBuilder += `ROOT DIRECTORY: [Unable to fetch - ${contentsRes.statusText}]\n\n`;
  }

  if (readmeRes.ok) {
    const data = await readmeRes.json();
    try {
      const binaryString = atob(data.content.replace(/\s/g, ''));
      const bytes = new Uint8Array(binaryString.length);
      for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      const decodedReadme = new TextDecoder().decode(bytes);
      contextBuilder += `README.md CONTENT:\n${decodedReadme}\n\n`;
    } catch (e) {
      contextBuilder += `README.md CONTENT: [Error decoding content]\n\n`;
    }
  } else {
    contextBuilder += `README.md: [Not found or unable to fetch]\n\n`;
  }

  return contextBuilder;
};
