import { GoogleGenAI, Type } from "@google/genai";
import { TodoItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a Senior Principal Software Architect specialized in reviewing specialized repositories like "Ada-Stargate". 
Your goal is to analyze project descriptions, file structures, and readme content to generate a concrete, actionable "Todo" list for improvements.

You will be provided with a text block that may contain:
1. Repository Name
2. Root File Structure
3. Readme Content
4. Additional User Context

Analyze this data to infer the technology stack (e.g., React, Rust, Cardano, TypeScript), architectural patterns, and potential gaps.
Focus on high-impact changes, modern best practices (React 18+, Performance, Security, Accessibility), and maintainability.

If the Readme is sparse, use the file structure to infer the project type and suggest standard industry-standard best practices for that type of project.

Output MUST be strict JSON matching the schema.
`;

export const analyzeRepoAndGetTasks = async (
  context: string,
  focus?: string
): Promise<TodoItem[]> => {
  try {
    const prompt = `
    Analyze the following project context and suggest specific improvements. 

    === BEGIN CONTEXT ===
    ${context}
    === END CONTEXT ===

    ${focus ? `\nSpecific Focus Area for Analysis: "${focus}"` : ''}

    Based on this, generate a list of 6-10 specific, actionable improvement tasks.
    Ensure the "rationale" field explains *why* based on the provided context (e.g., "Saw 'var' in snippet", "Readme missing setup instructions", "File structure lacks tests folder").
    `;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING },
              category: { 
                type: Type.STRING, 
                enum: [
                  "Architecture",
                  "Refactoring",
                  "Features",
                  "Security",
                  "UI/UX",
                  "Documentation"
                ] 
              },
              priority: {
                type: Type.STRING,
                enum: ["High", "Medium", "Low"]
              },
              rationale: { type: Type.STRING }
            },
            required: ["title", "description", "category", "priority", "rationale"]
          }
        }
      },
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("No data returned from Gemini");

    const rawData = JSON.parse(jsonText);

    return rawData.map((item: any, index: number) => ({
      ...item,
      id: `generated-${Date.now()}-${index}`,
      status: 'pending'
    }));

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};
