import { analyzeRepoAndGetTasks } from './services/geminiService';
import { fetchGitHubRepoContext } from './services/githubService';
import { TodoItem } from './types';
import { Github, Zap, Radio, Globe } from 'lucide-react';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<TodoItem[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [statusMessage, setStatusMessage] = useState<string>('');
  const [error, setError] = useState<string | null>(null);

  const handleAnalysis = useCallback(async (repoUrl: string, manualContext: string, focus: string) => {
    setIsLoading(true);
    setError(null);
    setTasks([]);

    try {
      let combinedContext = "";

      if (repoUrl.trim()) {
        setStatusMessage(`Targeting Repository: ${repoUrl}...`);
        try {
           const repoData = await fetchGitHubRepoContext(repoUrl);
           combinedContext += repoData + "\n\n";
           setStatusMessage("Repository Data Acquired. Parsing...");
        } catch (fetchErr: any) {
           console.warn("GitHub fetch warning:", fetchErr);
           combinedContext += `[Warning: Could not fetch automatic data from ${repoUrl}. Error: ${fetchErr.message}]\n\n`;
        }
      }

      if (manualContext.trim()) {
        combinedContext += `ADDITIONAL USER CONTEXT:\n${manualContext}`;
      }

      if (!combinedContext.trim()) {
        throw new Error("No context available for analysis. Please provide a valid GitHub URL or manual context.");
      }

      setStatusMessage("Engaging Gemini AI Neural Link...");
      const generatedTasks = await analyzeRepoAndGetTasks(combinedContext, focus);
      setTasks(generatedTasks);

    } catch (err: any) {
      setError(err.message || "Sequence Failed: Unable to establish stable connection.");
    } finally {
      setIsLoading(false);
      setStatusMessage('');
    }
