interface ChatInterfaceProps {
    messages: Message[];
    activeChannel: string;
    isLoading: boolean;
    selectedModel: ModelType;
    userRole: any;
    onModelChange: (m: ModelType) => void;
    onSend: (text: string, attachments: File[]) => void;
