                        mooringLine2 = `M ${b.cx+4} ${b.cy+20} L ${b.cx+8} ${b.cy+35}`;
                        passY2 = b.cy + 4; // Gangway down
                        labelY += 15;
                    } 
                    else if (b.orientation === 'up') {
                        // Stern at Pontoon North Edge (y), Bow pointing North (y-)
