// services/WorkflowEngine.ts

async function transitionState(reservationId: string, newState: ReservationStatus) {
  const reservation = await db.getReservation(reservationId);

  // KURAL 1: Evraklar tam olmadan tekne bağlanamaz.
  if (newState === ReservationStatus.CHECKED_IN && reservation.status === ReservationStatus.REQUESTED) {
    const docs = await db.checkDocuments(reservation.boatId);
    if (!docs.insuranceValid) {
      throw new Error("SİGORTA POLİÇESİ EKSİK! Giriş yapılamaz.");
    }
  }

  // KURAL 2: Borç ödenmeden çıkış yapılamaz.
  if (newState === ReservationStatus.CHECKED_OUT) {
    const balance = await FinanceService.getBalance(reservation.boatId);
    if (balance > 0) {
      throw new Error(`ÇIKIŞ REDDEDİLDİ. ${balance} EUR bakiye var. Muhasebeye yönlendir.`);
    }
  }

  // Geçiş serbest ise durumu güncelle
  await db.updateStatus(reservationId, newState);

  // DOMAIN EVENT: Durum değiştiğinde diğer servisleri tetikle
  if (newState === ReservationStatus.CHECKED_IN) {
    // Otomatik olarak elektrik sayacını aç
    IoTService.activatePedestal(reservation.berthId);
  }
}
